# 提取所有SVG
while i < len(lines):
    line = lines[i].strip()

    if line.startswith('【插图'):
        desc = line

        if i + 1 < len(lines) and '<svg' in lines[i + 1]:
            svg_start = i + 1
            svg_end = svg_start
            svg_lines = []

            while svg_end < len(lines):
                svg_lines.append(lines[svg_end])
                if '</svg>' in lines[svg_end]:
                    break
                svg_end += 1

            if svg_end < len(lines):
                svg_content = '\n'.join(svg_lines)
                svg_id = len(svg_list) + 1

                svg_list.append({
                    'id': svg_id,
                    'desc': desc,
                    'svg_content': svg_content
                })

                i = svg_end

    i += 1
